import{_ as a}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as o,o as r,c as n,a2 as i}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Configuración del Cloudflare API Token","description":"","frontmatter":{},"headers":[],"relativePath":"es/Safety/cloudflare-api-token.md","filePath":"es/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),t={name:"es/Safety/cloudflare-api-token.md"};function l(d,e,s,c,u,p){return r(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="configuracion-del-cloudflare-api-token" tabindex="-1">Configuración del Cloudflare API Token <a class="header-anchor" href="#configuracion-del-cloudflare-api-token" aria-label="Permalink to &quot;Configuración del Cloudflare API Token&quot;">​</a></h1><p>Algunas funciones de ImgBed necesitan un Cloudflare API Token. Por ejemplo, se usa al trabajar con recursos como R2, Workers, D1 o KV.</p><h2 id="que-preparar" tabindex="-1">Qué preparar <a class="header-anchor" href="#que-preparar" aria-label="Permalink to &quot;Qué preparar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requisito</th><th>Uso</th></tr></thead><tbody><tr><td>Cuenta de Cloudflare</td><td>Crear el API Token</td></tr><tr><td>Account ID</td><td>Identificar la cuenta donde están R2, Workers u otros recursos</td></tr><tr><td>Permisos necesarios</td><td>Dar solo los permisos requeridos por la función</td></tr></tbody></table><h2 id="crear-un-api-token" tabindex="-1">Crear un API Token <a class="header-anchor" href="#crear-un-api-token" aria-label="Permalink to &quot;Crear un API Token&quot;">​</a></h2><ol><li>Inicia sesión en Cloudflare Dashboard.</li><li>Abre <code>My Profile</code> desde el perfil de la esquina superior derecha.</li><li>Entra en <code>API Tokens</code>.</li><li>Haz clic en <code>Create Token</code>.</li><li>Selecciona los permisos necesarios.</li><li>Limita el token a la cuenta o zona correspondiente.</li><li>Copia el token generado.</li></ol><p>![Cloudflare API Token](../../image/Safety/cloudflare api token截图.png)</p><p>El token puede mostrarse solo una vez. Guárdalo en un lugar seguro.</p><h2 id="diferencia-con-global-api-key" tabindex="-1">Diferencia con Global API Key <a class="header-anchor" href="#diferencia-con-global-api-key" aria-label="Permalink to &quot;Diferencia con Global API Key&quot;">​</a></h2><p>Cloudflare también ofrece Global API Key, pero para ImgBed suele ser mejor usar API Token.</p><table tabindex="0"><thead><tr><th>Tipo</th><th>Característica</th></tr></thead><tbody><tr><td>API Token</td><td>Permite limitar permisos y alcance</td></tr><tr><td>Global API Key</td><td>Tiene permisos muy amplios sobre la cuenta</td></tr></tbody></table><p>Un API Token con permisos mínimos reduce riesgos en operación.</p><p><img src="'+a+'" alt="Ver Global API Key" loading="lazy"></p><h2 id="introducirlo-en-imgbed" tabindex="-1">Introducirlo en ImgBed <a class="header-anchor" href="#introducirlo-en-imgbed" aria-label="Permalink to &quot;Introducirlo en ImgBed&quot;">​</a></h2><p>Pega el Cloudflare API Token en la pantalla de configuración correspondiente de ImgBed y guarda.</p><p>Después, usa la función relacionada para comprobar conexión o capacidad y confirmar que el token funciona.</p><h2 id="buenas-practicas" tabindex="-1">Buenas prácticas <a class="header-anchor" href="#buenas-practicas" aria-label="Permalink to &quot;Buenas prácticas&quot;">​</a></h2><ul><li>No pongas el token en repositorios públicos ni en código frontend.</li><li>Limita permisos y recursos todo lo posible.</li><li>Elimina en Cloudflare los tokens que ya no uses.</li><li>Si sospechas que se filtró, revócalo y crea uno nuevo.</li></ul>',18)])])}const b=o(t,[["render",l]]);export{h as __pageData,b as default};
